-- BOOTSTRAP-NAV-MOBILE-CATALOG: promote mobile screens + mode-pills into
-- the admin-manageable nav_catalog (generated by services/gateway/scripts/gen-mobile-nav-seed.ts).
-- Additive + idempotent: upserts keyed on the screen_id shared-unique index;
-- only screen_ids absent from the DB at generation time are included, so existing
-- rows / admin edits are never touched. Overlays + developer screens excluded.
-- 109 screens.
BEGIN;

-- HOME.NEWS_ALL
WITH up AS (
  INSERT INTO nav_catalog (screen_id, tenant_id, route, category, access, anonymous_safe, priority, related_kb_topics, is_active)
  VALUES ('HOME.NEWS_ALL', NULL, '/home?tab=all', 'home', 'authenticated', FALSE, 0, '[]'::jsonb, TRUE)
  ON CONFLICT (screen_id) WHERE tenant_id IS NULL
  DO UPDATE SET updated_at = now()
  RETURNING id
)
INSERT INTO nav_catalog_i18n (catalog_id, lang, title, description, when_to_visit)
SELECT up.id, v.lang, v.title, v.description, v.wtv
FROM up CROSS JOIN (VALUES
    ('en', 'All News', 'The News feed with all sources — longevity and community news combined.', 'When the user asks for the All News tab, all news, every news source, or both longevity and community news together in one feed.'),
    ('de', 'Alle News', 'Der News-Feed mit allen Quellen — Longevity- und Community-News zusammen.', 'Wenn der Nutzer den Tab „Alle News“, alle Nachrichten, jede Nachrichtenquelle oder Longevity- und Community-News zusammen in einem Feed möchte.')
) AS v(lang, title, description, wtv)
ON CONFLICT (catalog_id, lang) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, when_to_visit = EXCLUDED.when_to_visit;

